 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import {
 4	  DescriptionListDescription,
 5	  DescriptionListGroup,
 6	  DescriptionListTerm,
 7	} from '@patternfly/react-core';
 8	
 9	/**
10	 * A wrapper around PatternFly's description group. This component's parent must
11	 * be a PatternFly DescriptionList.
12	 */
13	export const MirroringCardItem: React.FC<MirroringCardItemProps> = React.memo(
14	  ({
15	    title,
16	    isLoading = false,
17	    children,
18	    error = false,
19	    valueClassName,
20	    errorMessage,
21	  }) => {
22	    const { t } = useCustomTranslation();
23	
24	    let status: React.ReactNode;
25	
26	    if (error) {
27	      status = (
28	        <span className="text-secondary">
29	          {errorMessage || t('Not available')}
30	        </span>
31	      );
32	    } else if (isLoading) {
33	      status = <div className="skeleton-text" />;
34	    } else {
35	      status = children;
36	    }
37	    return (
38	      <DescriptionListGroup>
39	        {title && (
40	          <DescriptionListTerm data-test="mirroring-card-item-title">
41	            {title}
42	          </DescriptionListTerm>
43	        )}
44	        <DescriptionListDescription
45	          className={valueClassName}
46	          data-test="mirroring-card-item-value"
47	        >
48	          {status}
49	        </DescriptionListDescription>
50	      </DescriptionListGroup>
51	    );
52	  }
53	);
54	
55	MirroringCardItem.displayName = 'MirroringCardItem';
56	
57	type MirroringCardItemProps = {
58	  children: React.ReactNode;
59	  title?: string;
60	  isLoading?: boolean;
61	  error?: boolean;
62	  valueClassName?: string;
63	  errorMessage?: string;
64	};

